// JavaScript (Duck Typing)
function makeSound(creature) {
  // We don't care if 'creature' is a Dog, Cat, or Robot.
  // We only care if it has a 'quack' method.
  if (typeof creature.quack === 'function') {
    creature.quack();
  }
